/**
 * Tests for IntelVisibilityService
 *
 * Coverage:
 * - Visibility checks for all visibility levels
 * - Role-based access control
 * - Caching behavior
 * - Audit logging
 * - Edge cases (missing roles, cross-org attempts)
 */

import {
  IntelVisibilityLevel,
  IntelVisibilityService,
} from '../../../services/intel/IntelVisibilityService';
import { ForbiddenError, NotFoundError } from '../../../utils/apiErrors';

// ─── Mock Setup ───────────────────────────────────────────────────────────

const mockIntelRepo = {
  findOne: jest.fn(),
  createQueryBuilder: jest.fn(),
};

const mockMembershipRepo = {
  findOne: jest.fn(),
};

const mockAuditLogRepo = {
  create: jest.fn(),
  save: jest.fn(),
};

jest.mock('../../../data-source', () => ({
  AppDataSource: {
    getRepository: jest.fn((entity: Record<string, unknown>) => {
      if (entity.name === 'IntelEntry') return mockIntelRepo;
      if (entity.name === 'OrganizationMembership') return mockMembershipRepo;
      if (entity.name === 'IntelAuditLog') return mockAuditLogRepo;
      return {};
    }),
  },
}));

jest.mock('../../../services/intel/IntelAuditLogger');

// ─── Test Suite ─────────────────────────────────────────────────────────

describe('IntelVisibilityService', () => {
  let service: IntelVisibilityService;
  const TEST_ORG_ID = 'org-123';
  const TEST_USER_ID = 'user-abc';
  const TEST_INTEL_ID = 'intel-xyz';

  beforeEach(() => {
    jest.clearAllMocks();
    service = new IntelVisibilityService();
    // Clear cache before each test
    service.clearRoleCache(TEST_USER_ID, TEST_ORG_ID);
  });

  // ─── Visibility Check Tests ───────────────────────────────────────────

  describe('canViewIntel()', () => {
    it('should allow viewing PUBLIC intel for any user', async () => {
      mockIntelRepo.findOne.mockResolvedValue({
        id: TEST_INTEL_ID,
        organizationId: TEST_ORG_ID,
        visibilityLevel: IntelVisibilityLevel.PUBLIC,
      });

      const result = await service.canViewIntel(TEST_USER_ID, TEST_INTEL_ID, TEST_ORG_ID);

      expect(result.canView).toBe(true);
      expect(result.visibilityLevel).toBe(IntelVisibilityLevel.PUBLIC);
    });

    it('should allow ORG-level intel for org members', async () => {
      mockIntelRepo.findOne.mockResolvedValue({
        id: TEST_INTEL_ID,
        visibilityLevel: IntelVisibilityLevel.ORG,
      });
      mockMembershipRepo.findOne.mockResolvedValue({
        userId: TEST_USER_ID,
        userRole: { name: 'member' },
      });

      const result = await service.canViewIntel(TEST_USER_ID, TEST_INTEL_ID, TEST_ORG_ID);

      expect(result.canView).toBe(true);
    });

    it('should deny ORG-level intel for non-members', async () => {
      mockIntelRepo.findOne.mockResolvedValue({
        id: TEST_INTEL_ID,
        visibilityLevel: IntelVisibilityLevel.ORG,
      });
      mockMembershipRepo.findOne.mockResolvedValue(null); // Not a member

      const result = await service.canViewIntel(TEST_USER_ID, TEST_INTEL_ID, TEST_ORG_ID);

      expect(result.canView).toBe(false);
    });

    it('should allow PRIVATE intel for creator', async () => {
      mockIntelRepo.findOne.mockResolvedValue({
        id: TEST_INTEL_ID,
        visibilityLevel: IntelVisibilityLevel.PRIVATE,
        createdBy: TEST_USER_ID,
      });
      mockMembershipRepo.findOne.mockResolvedValue({
        userRole: { name: 'member' },
      });

      const result = await service.canViewIntel(TEST_USER_ID, TEST_INTEL_ID, TEST_ORG_ID);

      expect(result.canView).toBe(true);
    });

    it('should allow PRIVATE intel for admins', async () => {
      mockIntelRepo.findOne.mockResolvedValue({
        id: TEST_INTEL_ID,
        visibilityLevel: IntelVisibilityLevel.PRIVATE,
        createdBy: 'other-user',
      });
      mockMembershipRepo.findOne.mockResolvedValue({
        userRole: { name: 'admin' },
      });

      const result = await service.canViewIntel(TEST_USER_ID, TEST_INTEL_ID, TEST_ORG_ID);

      expect(result.canView).toBe(true);
    });

    it('should deny PRIVATE intel for non-creator members', async () => {
      mockIntelRepo.findOne.mockResolvedValue({
        id: TEST_INTEL_ID,
        visibilityLevel: IntelVisibilityLevel.PRIVATE,
        createdBy: 'other-user',
      });
      mockMembershipRepo.findOne.mockResolvedValue({
        userRole: { name: 'member' },
      });

      const result = await service.canViewIntel(TEST_USER_ID, TEST_INTEL_ID, TEST_ORG_ID);

      expect(result.canView).toBe(false);
    });

    it('should return false for non-existent intel', async () => {
      mockIntelRepo.findOne.mockResolvedValue(null);

      const result = await service.canViewIntel(TEST_USER_ID, TEST_INTEL_ID, TEST_ORG_ID);

      expect(result.canView).toBe(false);
    });

    it('should handle cross-org access attempts', async () => {
      mockIntelRepo.findOne.mockResolvedValue(null);

      const result = await service.canViewIntel(TEST_USER_ID, TEST_INTEL_ID, 'different-org');

      expect(result.canView).toBe(false);
    });
  });

  // ─── Role Caching Tests ───────────────────────────────────────────────

  describe('role caching', () => {
    it('should cache user roles for 1 hour', async () => {
      mockMembershipRepo.findOne.mockResolvedValue({
        userRole: { name: 'officer' },
      });

      // First call should query DB
      await service.canViewIntel(TEST_USER_ID, TEST_INTEL_ID, TEST_ORG_ID);
      expect(mockMembershipRepo.findOne).toHaveBeenCalledTimes(1);

      // Reset mock
      mockMembershipRepo.findOne.mockClear();

      // Second call (within 1 hour) should use cache
      mockIntelRepo.findOne.mockResolvedValue({
        visibilityLevel: IntelVisibilityLevel.ORG,
      });
      await service.canViewIntel(TEST_USER_ID, TEST_INTEL_ID, TEST_ORG_ID);

      // DB should not be queried again for membership
      expect(mockMembershipRepo.findOne).toHaveBeenCalledTimes(0);
    });

    it('should invalidate cache on clearRoleCache()', async () => {
      mockMembershipRepo.findOne.mockResolvedValue({
        userRole: { name: 'member' },
      });

      // Warm cache
      await service.canViewIntel(TEST_USER_ID, TEST_INTEL_ID, TEST_ORG_ID);

      // Clear cache
      service.clearRoleCache(TEST_USER_ID, TEST_ORG_ID);

      // Reset mock to track new calls
      mockMembershipRepo.findOne.mockClear();

      // Next call should query DB again
      mockIntelRepo.findOne.mockResolvedValue({
        visibilityLevel: IntelVisibilityLevel.ORG,
      });
      await service.canViewIntel(TEST_USER_ID, TEST_INTEL_ID, TEST_ORG_ID);

      expect(mockMembershipRepo.findOne).toHaveBeenCalled();
    });
  });

  // ─── Get Visible Entries Tests ───────────────────────────────────────

  describe('getVisibleIntelEntries()', () => {
    it('should return PUBLIC intel for all users', async () => {
      const mockQueryBuilder = {
        where: jest.fn().mockReturnThis(),
        andWhere: jest.fn().mockReturnThis(),
        setParameter: jest.fn().mockReturnThis(),
        orderBy: jest.fn().mockReturnThis(),
        limit: jest.fn().mockReturnThis(),
        offset: jest.fn().mockReturnThis(),
        getManyAndCount: jest
          .fn()
          .mockResolvedValue([[{ id: '1', visibilityLevel: IntelVisibilityLevel.PUBLIC }], 1]),
      };

      mockMembershipRepo.findOne.mockResolvedValue(null); // Guest user
      mockIntelRepo.createQueryBuilder.mockReturnValue(mockQueryBuilder);

      const result = await service.getVisibleIntelEntries(TEST_ORG_ID, TEST_USER_ID);

      expect(result.entries).toHaveLength(1);
      expect(result.total).toBe(1);
    });

    it('should filter by search query', async () => {
      const mockQueryBuilder = {
        where: jest.fn().mockReturnThis(),
        andWhere: jest.fn().mockReturnThis(),
        setParameter: jest.fn().mockReturnThis(),
        orderBy: jest.fn().mockReturnThis(),
        limit: jest.fn().mockReturnThis(),
        offset: jest.fn().mockReturnThis(),
        getManyAndCount: jest.fn().mockResolvedValue([[], 0]),
      };

      mockMembershipRepo.findOne.mockResolvedValue({
        userRole: { name: 'member' },
      });
      mockIntelRepo.createQueryBuilder.mockReturnValue(mockQueryBuilder);

      await service.getVisibleIntelEntries(TEST_ORG_ID, TEST_USER_ID, {
        search: 'test',
      });

      // Should call andWhere for search filter
      expect(mockQueryBuilder.andWhere).toHaveBeenCalled();
    });

    it('should respect pagination limits', async () => {
      const mockQueryBuilder = {
        where: jest.fn().mockReturnThis(),
        andWhere: jest.fn().mockReturnThis(),
        setParameter: jest.fn().mockReturnThis(),
        orderBy: jest.fn().mockReturnThis(),
        limit: jest.fn().mockReturnThis(),
        offset: jest.fn().mockReturnThis(),
        getManyAndCount: jest.fn().mockResolvedValue([[], 0]),
      };

      mockMembershipRepo.findOne.mockResolvedValue({
        userRole: { name: 'member' },
      });
      mockIntelRepo.createQueryBuilder.mockReturnValue(mockQueryBuilder);

      await service.getVisibleIntelEntries(TEST_ORG_ID, TEST_USER_ID, {
        limit: 25,
        offset: 50,
      });

      expect(mockQueryBuilder.limit).toHaveBeenCalledWith(25);
      expect(mockQueryBuilder.offset).toHaveBeenCalledWith(50);
    });
  });

  // ─── Get Entry Details Tests ──────────────────────────────────────────

  describe('getIntelDetails()', () => {
    it('should return intel if user has view permission', async () => {
      const intelData = { id: TEST_INTEL_ID, visibilityLevel: IntelVisibilityLevel.PUBLIC };
      mockIntelRepo.findOne.mockResolvedValue(intelData);
      mockMembershipRepo.findOne.mockResolvedValue(null);

      const result = await service.getIntelDetails(TEST_INTEL_ID, TEST_ORG_ID, TEST_USER_ID);

      expect(result).toEqual(intelData);
    });

    it('should throw ForbiddenError if user lacks permission', async () => {
      mockIntelRepo.findOne.mockResolvedValue({
        visibilityLevel: IntelVisibilityLevel.PRIVATE,
        createdBy: 'other-user',
      });
      mockMembershipRepo.findOne.mockResolvedValue({ userRole: { name: 'member' } });

      await expect(
        service.getIntelDetails(TEST_INTEL_ID, TEST_ORG_ID, TEST_USER_ID)
      ).rejects.toThrow(ForbiddenError);
    });

    it('should throw NotFoundError if intel does not exist', async () => {
      mockIntelRepo.findOne.mockResolvedValueOnce(null);
      mockIntelRepo.findOne.mockResolvedValueOnce(null);
      mockMembershipRepo.findOne.mockResolvedValue(null);

      await expect(
        service.getIntelDetails(TEST_INTEL_ID, TEST_ORG_ID, TEST_USER_ID)
      ).rejects.toThrow(NotFoundError);
    });
  });

  // ─── Update Visibility Tests ──────────────────────────────────────────

  describe('updateIntelVisibility()', () => {
    it('should allow admins to update visibility', async () => {
      mockIntelRepo.findOne.mockResolvedValue({
        id: TEST_INTEL_ID,
        visibilityLevel: IntelVisibilityLevel.ORG,
      });
      mockIntelRepo.save.mockResolvedValue({
        id: TEST_INTEL_ID,
        visibilityLevel: IntelVisibilityLevel.PRIVATE,
      });
      mockMembershipRepo.findOne.mockResolvedValue({
        userRole: { name: 'admin' },
      });

      const result = await service.updateIntelVisibility(
        TEST_INTEL_ID,
        TEST_ORG_ID,
        TEST_USER_ID,
        IntelVisibilityLevel.PRIVATE
      );

      expect(result.visibilityLevel).toBe(IntelVisibilityLevel.PRIVATE);
      expect(mockIntelRepo.save).toHaveBeenCalled();
    });

    it('should deny non-admins from updating visibility', async () => {
      mockMembershipRepo.findOne.mockResolvedValue({
        userRole: { name: 'member' },
      });

      await expect(
        service.updateIntelVisibility(
          TEST_INTEL_ID,
          TEST_ORG_ID,
          TEST_USER_ID,
          IntelVisibilityLevel.PRIVATE
        )
      ).rejects.toThrow(ForbiddenError);
    });

    it('should throw NotFoundError if intel does not exist', async () => {
      mockMembershipRepo.findOne.mockResolvedValue({
        userRole: { name: 'admin' },
      });
      mockIntelRepo.findOne.mockResolvedValue(null);

      await expect(
        service.updateIntelVisibility(
          TEST_INTEL_ID,
          TEST_ORG_ID,
          TEST_USER_ID,
          IntelVisibilityLevel.PRIVATE
        )
      ).rejects.toThrow(NotFoundError);
    });
  });

  // ─── Edge Cases ───────────────────────────────────────────────────────

  describe('edge cases', () => {
    it('should handle missing organization membership gracefully', async () => {
      mockIntelRepo.findOne.mockResolvedValue({
        visibilityLevel: IntelVisibilityLevel.ORG,
      });
      mockMembershipRepo.findOne.mockResolvedValue(null);

      const result = await service.canViewIntel(TEST_USER_ID, TEST_INTEL_ID, TEST_ORG_ID);

      expect(result.canView).toBe(false);
    });

    it('should handle database errors gracefully', async () => {
      mockIntelRepo.findOne.mockRejectedValue(new Error('DB Error'));

      await expect(
        service.canViewIntel(TEST_USER_ID, TEST_INTEL_ID, TEST_ORG_ID)
      ).rejects.toThrow();
    });

    it('should default to ORG visibility if not specified', async () => {
      mockIntelRepo.findOne.mockResolvedValue({
        id: TEST_INTEL_ID,
        // visibilityLevel not set, should default to ORG
      });
      mockMembershipRepo.findOne.mockResolvedValue({
        userRole: { name: 'member' },
      });

      const result = await service.canViewIntel(TEST_USER_ID, TEST_INTEL_ID, TEST_ORG_ID);

      expect(result.canView).toBe(true);
    });

    it('should map various admin role names', async () => {
      mockIntelRepo.findOne.mockResolvedValue({
        visibilityLevel: IntelVisibilityLevel.ORG,
      });
      mockMembershipRepo.findOne.mockResolvedValue({
        userRole: { name: 'org_admin' }, // Variant role name
      });

      const result = await service.canViewIntel(TEST_USER_ID, TEST_INTEL_ID, TEST_ORG_ID);

      expect(result.canView).toBe(true); // Admin can see ORG-level
    });
  });
});
